CREATE OR REPLACE PROCEDURE dbhcen.atualizarcodigounico()
 LANGUAGE plpgsql
AS $procedure$
   DECLARE
   v_sNumeroInstr  CHAR(8);   
   v_nHabilitado  NUMERIC(12,0);   
   
   
   cur1 cursor for    
   select distinct a.nHabilitado   
   from dbhcen.REGISTROINSTRUTORCFC a    
   order by a.nHabilitado asc;
BEGIN
